create table accounts (id uuid primary key, customer_id uuid not null, type varchar(20) not null, status varchar(20) not null, balance numeric(19,2) not null, currency varchar(3) not null, version bigint not null default 0, created_at timestamptz not null, updated_at timestamptz not null);
create table ledger_entries (id uuid primary key, account_id uuid not null references accounts(id), operation_id uuid not null unique, idempotency_key varchar(100) not null unique, type varchar(30) not null, amount numeric(19,2) not null, balance_after numeric(19,2) not null, description varchar(255) not null, occurred_at timestamptz not null);
create index idx_ledger_account_time on ledger_entries(account_id, occurred_at desc);
create table outbox_events (id uuid primary key, aggregate_id uuid not null, aggregate_type varchar(80) not null, event_type varchar(100) not null, payload text not null, status varchar(20) not null, attempts integer not null default 0, next_attempt_at timestamptz not null, created_at timestamptz not null, published_at timestamptz, last_error varchar(500));
create index idx_outbox_pending on outbox_events(status, next_attempt_at, created_at);
create table processed_events (event_id uuid primary key, consumer_name varchar(100) not null, processed_at timestamptz not null);
create table audit_events (id uuid primary key, event_id uuid not null unique, aggregate_id uuid not null, event_type varchar(100) not null, payload text not null, received_at timestamptz not null);
create table reconciliations (id uuid primary key, account_id uuid not null references accounts(id), account_balance numeric(19,2) not null, ledger_balance numeric(19,2) not null, difference numeric(19,2) not null, status varchar(20) not null, checked_at timestamptz not null);
